import { useState } from "react";
import Sidebar from "../components/Sidebar";
import AddServiceModal from "../components/AddServiceModal";
import EditServiceModal from "../components/EditServiceModal";
import DeleteServiceModal from "../components/DeleteServiceModal";
import ServiceDetailModal from "../components/ServiceDetailModal";
import Toast ,{useToast}from "../components/Toast";

const AVATAR_HEADER = "https://www.figma.com/api/mcp/asset/75e77366-d72b-489b-b204-cb2b3a0095d6";

const s = {
  page: { display: "flex", minHeight: "100vh", background: "#fff", fontFamily: "'Libre Bodoni', serif" },
  main: { marginLeft: 341, flex: 1, padding: "0 40px 40px" },

  // Top bar
  topBar: { display: "flex", alignItems: "center", justifyContent: "space-between", padding: "20px 0 0", borderBottom: "1px solid #e0d5c5", marginBottom: 28 },
  pageTitle: { fontSize: 36, fontWeight: 700, color: "#5f4a28" },
  userCard: { display: "flex", alignItems: "center", gap: 12, background: "#ecdcc2", borderRadius: 20, padding: "8px 20px" },
  userAvatar: { width: 48, height: 48, borderRadius: "50%", objectFit: "cover" },
  userName: { fontWeight: 700, fontSize: 18, color: "#5f4a28" },
  userRole: { fontSize: 14, color: "#5f4a28", opacity: 0.7 },

  // Section header
  sectionRow: { display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 20 },
  sectionTitle: { fontSize: 28, fontWeight: 700, color: "#5f4a28" },
  addBtn: {
    display: "flex", alignItems: "center", gap: 6, background: "#ecdcc2",
    border: "none", borderRadius: 20, padding: "8px 20px",
    fontFamily: "'Libre Bodoni', serif", fontSize: 18, fontWeight: 700,
    color: "#5f4a28", cursor: "pointer", transition: "background 0.2s",
  },

  // Table card
  tableCard: { background: "#faf3e8", borderRadius: 25, padding: "20px 24px" },
  tableTop: { display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 16 },
  tableLabel: { fontSize: 26, fontWeight: 400, color: "#5f4a28" },
  searchBox: {
    background: "#fff", border: "none", borderRadius: 20, padding: "4px 16px",
    fontSize: 16, fontFamily: "'Libre Bodoni', serif", color: "rgba(95,74,40,0.5)",
    width: 180, outline: "none",
  },

  // Table
  table: { width: "100%", borderCollapse: "collapse" },
  th: { textAlign: "left", fontSize: 18, fontWeight: 400, color: "#5f4a28", padding: "8px 12px", borderBottom: "1px solid #c8b89a" },
  td: { fontSize: 16, color: "rgba(95,74,40,0.8)", padding: "12px 12px", borderBottom: "1px solid #e0d5c5" },
  thActions: { textAlign: "right", fontSize: 18, fontWeight: 400, color: "#5f4a28", padding: "8px 12px", borderBottom: "1px solid #c8b89a" },
  tdActions: { textAlign: "right", padding: "12px 12px", borderBottom: "1px solid #e0d5c5" },

  editBtn: {
    background: "#fff", border: "none", borderRadius: 20, padding: "4px 16px",
    fontFamily: "'Libre Bodoni', serif", fontSize: 16, color: "#5f4a28",
    cursor: "pointer", marginRight: 8,
  },
  deleteBtn: {
    background: "#fff", border: "none", borderRadius: 20, padding: "4px 16px",
    fontFamily: "'Libre Bodoni', serif", fontSize: 16, color: "#e54949",
    cursor: "pointer",
  },

  // Pagination
  pagination: { display: "flex", alignItems: "center", justifyContent: "center", gap: 8, padding: "20px 0 8px" },
  pageBtn: (active) => ({
    width: 36, height: 32, borderRadius: 10, border: "none", cursor: "pointer",
    background: active ? "#ecdcc2" : "#fff",
    fontFamily: "'Libre Bodoni', serif", fontSize: 16, color: "rgba(95,74,40,0.8)",
  }),
  pageNav: {
    border: "none", background: "none", cursor: "pointer",
    fontFamily: "'Libre Bodoni', serif", fontSize: 16, color: "rgba(95,74,40,0.6)",
  },
  showing: { fontSize: 15, color: "rgba(95,74,40,0.8)", marginTop: 4 },
};

export default function ServicesPage({ onNavigate, services, setServices, onLogout }) {
  const { toast, showToast } = useToast();
  const [showAdd, setShowAdd] = useState(false);
  const [editTarget, setEditTarget] = useState(null);
  const [deleteTarget, setDeleteTarget] = useState(null);
  const [detailTarget, setDetailTarget] = useState(null);
  const [search, setSearch] = useState("");
  const [page, setPage] = useState(1);

  const filtered = services.filter(sv =>
    sv.name.toLowerCase().includes(search.toLowerCase())
  );
  const perPage = 4;
  const totalPages = Math.max(1, Math.ceil(filtered.length / perPage));
  const displayed = filtered.slice((page - 1) * perPage, page * perPage);

  const handleAdd = (form) => {
    setServices([...services, { ...form, id: Date.now() }]);
    showToast("Service added successfully!");
  };
  const handleEdit = (form) => {
    setServices(services.map(sv => sv.id === form.id ? form : sv));
    showToast("Service updated successfully!");
  };
  const handleDelete = () => {
    setServices(services.filter(sv => sv.id !== deleteTarget.id));
    showToast("Service deleted.", "info");
  };

  return (
    <div style={s.page} className="page-enter">
      <style>{`@import url('https://fonts.googleapis.com/css2?family=Libre+Bodoni:wght@400;700&display=swap');`}</style>
      <Sidebar activePage="services" onNavigate={onNavigate} onLogout={onLogout} />

      <main style={s.main} className="main-content">
        {/* Top bar */}
        <div style={s.topBar}>
          <div style={s.pageTitle}>Admin Dashboard</div>
          <div style={s.userCard}>
            <img src={AVATAR_HEADER} alt="Admin" style={s.userAvatar} />
            <div>
              <div style={s.userName}>Luiza Mocan</div>
              <div style={s.userRole}>Admin</div>
            </div>
            <span style={{ color: "#5f4a28" }}>▾</span>
          </div>
        </div>

        {/* Section heading */}
        <div style={s.sectionRow}>
          <div style={s.sectionTitle}>Services Management</div>
          <button style={s.addBtn} onClick={() => setShowAdd(true)}>＋ Add Service</button>
        </div>

        {/* Table card */}
        <div style={s.tableCard}>
          <div style={s.tableTop}>
            <span style={s.tableLabel}>Services</span>
            <input
              style={s.searchBox}
              placeholder="Search"
              value={search}
              onChange={(e) => { setSearch(e.target.value); setPage(1); }}
            />
          </div>

          <table style={s.table}>
            <thead>
              <tr>
                <th style={s.th}>Service</th>
                <th style={s.th}>Price</th>
                <th style={s.th}>Duration</th>
                <th style={s.thActions}>Actions</th>
              </tr>
            </thead>
            <tbody>
              {displayed.map(sv => (
                <tr key={sv.id} className="table-row">
                  <td style={s.td}>{sv.name}</td>
                  <td style={s.td}>{sv.price}</td>
                  <td style={s.td}>{sv.duration}</td>
                  <td style={s.tdActions}>
                    <button style={s.editBtn} onClick={() => setEditTarget(sv)}>Edit</button>
                    <button style={s.deleteBtn} onClick={() => setDeleteTarget(sv)}>Delete</button>
                    <button onClick={() => setDetailTarget(sv)} style={{ background: "none", border: "none", cursor: "pointer", color: "#5f4a28", fontSize: 18, marginLeft: 8, padding: "2px 6px", borderRadius: 8 }}>•••</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          {/* Pagination */}
          <div style={s.pagination}>
            <button style={s.pageNav} onClick={() => setPage(p => Math.max(1, p - 1))}>Previous</button>
            {Array.from({ length: totalPages }, (_, i) => (
              <button key={i + 1} style={s.pageBtn(page === i + 1)} onClick={() => setPage(i + 1)}>{i + 1}</button>
            ))}
            <button style={s.pageNav} onClick={() => setPage(p => Math.min(totalPages, p + 1))}>Next ›</button>
          </div>
          <div style={s.showing}>Showing {displayed.length} of {filtered.length} services</div>
        </div>
      </main>

      {showAdd    && <AddServiceModal    onClose={() => setShowAdd(false)}    onAdd={handleAdd} />}
      {editTarget && <EditServiceModal   onClose={() => setEditTarget(null)}  service={editTarget} onSave={handleEdit} />}
      {deleteTarget && <DeleteServiceModal onClose={() => setDeleteTarget(null)} onConfirm={handleDelete} />}
      <Toast message={toast?.message} type={toast?.type} />
      {detailTarget && <ServiceDetailModal service={detailTarget} onClose={() => setDetailTarget(null)} onEdit={(sv) => { setDetailTarget(null); setEditTarget(sv); }} onDelete={(sv) => { setDetailTarget(null); setDeleteTarget(sv); }} />}
    </div>
  );
}
